import tarfile  # import tarfile module which is used for extracting the tar file as specified in the task.
import os       # import os module and use os.path.isfile() to check if provided argument is a file or not

def extract(tar_name, destination):
    try:
        if os.path.isfile(destination):    # check if destionation  is available.
            tf = tarfile.open(tar_name)    
            tf.extractall(destination)
            tf.close()
        else : 
            raise Exception('Destination not Found')      

    except FileNotFoundError as e:
        print ("Error : File Not Found")
        return -1
    except Exception as e: 
        # print(e.args)  # args: the exception arguments, which can be a tuple or an error message string.
        print(f"Exception Error: {e}")
        return -2
    else:
        print("Success")